from datetime import datetime, timedelta

current_date_input = input()
birthdays = []

while True:
    birthday_input = input()
    if birthday_input == 'end':
        break
    birthdays.append(birthday_input)

current_date = datetime.strptime(current_date_input, "%Y-%m-%d")
next_month_date = current_date + timedelta(days=30)

upcoming_birthdays = []

for entry in birthdays:
    name, birthdate_str = entry.split(", ")
    birthdate = datetime.strptime(birthdate_str, "%Y-%m-%d")

    if current_date <= birthdate <= next_month_date:
        upcoming_birthdays.append((name, birthdate_str))

if upcoming_birthdays:
    print("Upcoming birthdays within the next 30 days:")
    for i, (name, birthdate_str) in enumerate(upcoming_birthdays, start=1):
        print(f"{i}. {name} - Birthday on {birthdate_str}")
else:
    print("No upcoming birthdays within the next 30 days.")
